        // Assert
        Assert.Equal(3, list.PageIndex);
    }

    [Theory]
    [InlineData(10, 5, 2)]
    [InlineData(11, 5, 3)]
    [InlineData(0, 5, 0)]
    [InlineData(1, 1, 1)]
    [InlineData(100, 10, 10)]
    [InlineData(7, 3, 3)]
    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
