using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        NotificationQueueHelper.DrainQueue();
        _service = new NotificationService();
    }

    public void Dispose()
    {
        _service.Dispose();
        NotificationQueueHelper.DrainQueue();
    }

    [Fact]
    public void SendNotification_ValidInput_EnqueuesNotification()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
        Assert.Contains("has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("'John Doe'", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "42", null, EntityOperation.UPDATE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("(ID: 42)", notification.Message);
    }

    [Fact]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Course", "5", "Biology", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("New Student 'Jane Smith' has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.UPDATE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student 'Jane Smith' has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.DELETE, "admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student 'Jane Smith' has been deleted", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var notification = _service.ReceiveNotification();

        // Assert
        Assert.Null(notification);
    }

    [Fact]
    public void ReceiveNotification_WithItems_ReturnsInOrder()
    {
        // Arrange
        _service.SendNotification("Student", "1", "First", EntityOperation.CREATE, "admin");
        _service.SendNotification("Course", "2", "Second", EntityOperation.UPDATE, "admin");
        _service.SendNotification("Department", "3", "Third", EntityOperation.DELETE, "admin");

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.NotNull(first);
        Assert.Equal("Student", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.NotNull(second);
        Assert.Equal("Course", second.EntityType);

        var third = _service.ReceiveNotification();
        Assert.NotNull(third);
        Assert.Equal("Department", third.EntityType);
    }

    [Fact]
    public void SendNotification_ExceedsCap_OldestRemoved()
    {
        // Arrange — enqueue 510 items (exceeds cap of 500)
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE, "admin");
        }

        // Act — count remaining items by draining
        int count = 0;
        while (_service.ReceiveNotification() != null)
        {
            count++;
        }

        // Assert — should be capped at 500
        Assert.True(count <= 500, $"Expected at most 500 notifications, but found {count}");
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert — MarkAsRead is a no-op, should not throw
        var exception = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert — Dispose is a no-op, should not throw
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_TwoParamOverload_DelegatesToFourParam()
    {
        // Arrange & Act — use the 4-parameter overload (without displayName)
        _service.SendNotification("Student", "99", EntityOperation.UPDATE, "testuser");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("99", notification.EntityId);
        Assert.Equal("UPDATE", notification.Operation);
        Assert.Equal("testuser", notification.CreatedBy);
        Assert.Contains("(ID: 99)", notification.Message);
    }
}

