    }

    [Fact]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Arrange
        using var context = TestDbContextHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.Equal(5, context.Instructors.Count());
    }

    [Fact]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Arrange
        using var context = TestDbContextHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.Equal(4, context.Departments.Count());
    }

    [Fact]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Arrange
        using var context = TestDbContextHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.Equal(7, context.Courses.Count());
    }

