    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Arrange
        using var context = TestDbContextHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.Equal(11, context.Enrollments.Count());
    }

