using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests;

public class HomeControllerTests : IDisposable
{
    private readonly HomeController _controller;

    public HomeControllerTests()
    {
        NotificationQueueHelper.DrainQueue();
        var context = TestDbContextHelper.CreateContext();
        _controller = new HomeController(context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        NotificationQueueHelper.DrainQueue();
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void About_NoStudents_ReturnsEmptyList()
    {
        // Act
        var result = _controller.About();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
        Assert.Empty(model);
    }

    [Fact]
    public void About_WithStudents_ReturnsGroupedByDate()
    {
        // Arrange
        using var context = TestDbContextHelper.CreateContext();
        using var controller = new HomeController(context);

        var date1 = new DateTime(2023, 9, 1);
        var date2 = new DateTime(2024, 1, 15);

        context.Students.Add(new Student { LastName = "Doe", FirstMidName = "John", EnrollmentDate = date1 });
        context.Students.Add(new Student { LastName = "Smith", FirstMidName = "Jane", EnrollmentDate = date1 });
        context.Students.Add(new Student { LastName = "Brown", FirstMidName = "Bob", EnrollmentDate = date2 });
        context.SaveChanges();

        // Act
        var result = controller.About();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
        Assert.Equal(2, model.Count);

        var group1 = model.Single(g => g.EnrollmentDate == date1);
        Assert.Equal(2, group1.StudentCount);

        var group2 = model.Single(g => g.EnrollmentDate == date2);
        Assert.Equal(1, group2.StudentCount);
    }

    [Fact]
    public void About_ReturnsViewResult()
    {
        // Act
        var result = _controller.About();

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Contact_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Contact();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.Equal("Your contact page.", viewResult.ViewData["Message"]);
    }

    [Fact]
    public void Contact_ReturnsViewResult()
    {
        // Act
        var result = _controller.Contact();

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Error_ReturnsViewResult()
    {
        // Act
        var result = _controller.Error();

        // Assert
        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Unauthorized_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Unauthorized();

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.Equal("You don't have permission to access this resource.", viewResult.ViewData["Message"]);
    }

    [Fact]
    public void Unauthorized_ReturnsViewResult()
    {
        // Act
        var result = _controller.Unauthorized();

        // Assert
        Assert.IsType<ViewResult>(result);
    }
}

using System;
using System.Text.Json;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests;

public class NotificationsControllerTests : IDisposable
{
    private readonly NotificationsController _controller;
    private readonly NotificationService _sender;

    public NotificationsControllerTests()
    {
        NotificationQueueHelper.DrainQueue();
        var context = TestDbContextHelper.CreateContext();
        _controller = new NotificationsController(context);
        _sender = new NotificationService();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _sender.Dispose();
        NotificationQueueHelper.DrainQueue();
    }

    private static JsonElement GetJsonElement(JsonResult jsonResult)
    {
        var json = JsonSerializer.Serialize(jsonResult.Value);
        return JsonDocument.Parse(json).RootElement;
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        var root = GetJsonElement(result);
        Assert.True(root.GetProperty("success").GetBoolean());
        Assert.Equal(0, root.GetProperty("count").GetInt32());
    }

    [Fact]
    public void GetNotifications_WithNotifications_ReturnsUpToTen()
    {
        // Arrange — send 15 notifications via the shared static queue
        for (int i = 0; i < 15; i++)
        {
            _sender.SendNotification("Student", i.ToString(), $"Student{i}", EntityOperation.CREATE, "admin");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var root = GetJsonElement(result);
        Assert.True(root.GetProperty("success").GetBoolean());
        Assert.Equal(10, root.GetProperty("count").GetInt32());
        Assert.Equal(10, root.GetProperty("notifications").GetArrayLength());
    }

    [Fact]
    public void GetNotifications_WithFewNotifications_ReturnsAll()
    {
        // Arrange — send 3 notifications
        for (int i = 0; i < 3; i++)
        {
            _sender.SendNotification("Course", i.ToString(), $"Course{i}", EntityOperation.UPDATE, "admin");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var root = GetJsonElement(result);
        Assert.True(root.GetProperty("success").GetBoolean());
        Assert.Equal(3, root.GetProperty("count").GetInt32());
        Assert.Equal(3, root.GetProperty("notifications").GetArrayLength());
    }

    [Fact]
    public void GetNotifications_ReturnsJsonResult()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsType<JsonResult>(result);
    }

    [Fact]
    public void MarkAsRead_ReturnsSuccessTrue()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        var root = GetJsonElement(result);
        Assert.True(root.GetProperty("success").GetBoolean());
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsType<ViewResult>(result);
    }
}

using System;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests;

public class BaseControllerTests : IDisposable
{
    private readonly TestableController _controller;
    private readonly NotificationService _receiver;

    public BaseControllerTests()
    {
        NotificationQueueHelper.DrainQueue();
        var context = TestDbContextHelper.CreateContext();
        _controller = new TestableController(context);
        _receiver = new NotificationService();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _receiver.Dispose();
        NotificationQueueHelper.DrainQueue();
    }

    [Fact]
    public void SendEntityNotification_TwoParams_EnqueuesNotification()
    {
        // Act
        _controller.TestSendEntityNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _receiver.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("42", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("(ID: 42)", notification.Message);
    }

    [Fact]
    public void SendEntityNotification_ThreeParams_EnqueuesNotificationWithDisplayName()
    {
        // Act
        _controller.TestSendEntityNotification("Course", "101", "Biology", EntityOperation.UPDATE);

        // Assert
        var notification = _receiver.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Course", notification.EntityType);
        Assert.Equal("101", notification.EntityId);
        Assert.Equal("UPDATE", notification.Operation);
        Assert.Contains("'Biology'", notification.Message);
    }

    [Fact]
    public void SendEntityNotification_SetsUserNameToSystem()
    {
        // Act
        _controller.TestSendEntityNotification("Department", "5", EntityOperation.DELETE);

        // Assert
        var notification = _receiver.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void Dispose_DisposesContextAndService()
    {
        // Arrange
        var context = TestDbContextHelper.CreateContext();
        var controller = new TestableController(context);

        // Act & Assert — Dispose should not throw
        var exception = Record.Exception(() => controller.TestDispose());
        Assert.Null(exception);
    }

    /// <summary>
    /// Concrete subclass that exposes protected BaseController methods for testing.
    /// </summary>
    private class TestableController : BaseController
    {
        public TestableController(SchoolContext context) : base(context) { }

        public void TestSendEntityNotification(string entityType, string entityId, EntityOperation operation)
            => SendEntityNotification(entityType, entityId, operation);

        public void TestSendEntityNotification(string entityType, string entityId, string displayName, EntityOperation operation)
            => SendEntityNotification(entityType, entityId, displayName, operation);

        public void TestDispose() => Dispose(true);
    }
}

