    {
        _env = env;
        _logger = logger;
    }

    public ActionResult Index()
    {
        var courses = db.Courses.Include(c => c.Department);
        return View(courses.ToList());
    }

    public ActionResult Details(int? id)
    {
        if (id == null) { return new StatusCodeResult((int)HttpStatusCode.BadRequest); }
        Course course = db.Courses.Include(c => c.Department).Where(c => c.CourseID == id).Single();
        if (course == null) { return NotFound(); }
        return View(course);
    }

    public ActionResult Create()
    {
        ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name");
        return View(new Course());
    }

    [HttpPost]
    [ValidateAntiForgeryToken]
    public ActionResult Create([Bind(...)] Course course, IFormFile teachingMaterialImage)
    {
        if (ModelState.IsValid)
        {
            if (teachingMaterialImage != null && teachingMaterialImage.Length > 0)
            {
                var allowedExtensions = new[] { ".jpg", ".jpeg", ".png", ".gif", ".bmp" };
                var fileExtension = Path.GetExtension(teachingMaterialImage.FileName).ToLower();
                if (!allowedExtensions.Contains(fileExtension))
                {
                    ModelState.AddModelError("teachingMaterialImage", "Please upload a valid image file...");
                    ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
                    return View(course);
                }
                if (teachingMaterialImage.Length > 5 * 1024 * 1024)
                {
                    ModelState.AddModelError("teachingMaterialImage", "File size must be less than 5MB.");
                    ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
                    return View(course);
                }
                // ... file save logic
            }
            db.Courses.Add(course);
            db.SaveChanges();
            SendEntityNotification("Course", course.CourseID.ToString(), course.Title, EntityOperation.CREATE);
            return RedirectToAction("Index");
        }
        ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
        return View(course);
    }

    // Edit: similar to Create with file replace logic
    // Delete GET: returns course with department
    // DeleteConfirmed: removes course, deletes image file, sends notification
}
