using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        NotificationQueueHelper.DrainQueue();
        _context = TestDbContextHelper.CreateContext();
        _controller = new StudentsController(_context);

        // TempData is required for DeleteConfirmed (catch block sets TempData["ErrorMessage"])
        var httpContext = new DefaultHttpContext();
        var tempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
        _controller.TempData = tempData;
    }

    public void Dispose()
    {
        _controller.Dispose();
        NotificationQueueHelper.DrainQueue();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { LastName = "Zeta", FirstMidName = "Alice", EnrollmentDate = new DateTime(2023, 9, 1) },
            new Student { LastName = "Alpha", FirstMidName = "Bob", EnrollmentDate = new DateTime(2024, 1, 15) },
            new Student { LastName = "Mango", FirstMidName = "Charlie", EnrollmentDate = new DateTime(2022, 6, 1) }
        );
        _context.SaveChanges();
    }

    // ── Index Sorting ──────────────────────────────

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(3, model.Count);
        Assert.Equal("Alpha", model[0].LastName);
        Assert.Equal("Mango", model[1].LastName);
        Assert.Equal("Zeta", model[2].LastName);
    }

    [Fact]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("name_desc", null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Zeta", model[0].LastName);
        Assert.Equal("Mango", model[1].LastName);
        Assert.Equal("Alpha", model[2].LastName);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("Date", null, null, null);

        // Assert — 2022-06-01 < 2023-09-01 < 2024-01-15
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Charlie", model[0].FirstMidName);
        Assert.Equal("Alice", model[1].FirstMidName);
        Assert.Equal("Bob", model[2].FirstMidName);
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("date_desc", null, null, null);

        // Assert — 2024-01-15 > 2023-09-01 > 2022-06-01
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Bob", model[0].FirstMidName);
        Assert.Equal("Alice", model[1].FirstMidName);
        Assert.Equal("Charlie", model[2].FirstMidName);
    }

    // ── Index Search ───────────────────────────────

    [Fact]
    public void Index_SearchByLastName_FiltersStudents()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Alpha", null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alpha", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersStudents()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Alice", null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alice", model[0].FirstMidName);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Arrange
        SeedStudents();

        // Act — searchString is null, currentFilter is "Alpha"
        var result = _controller.Index(null, "Alpha", null, null);

        // Assert — should filter using currentFilter
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alpha", model[0].LastName);
    }

    [Fact]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        // Arrange
        SeedStudents();

        // Act — new searchString resets page to 1 even though page=5 is passed
        var result = _controller.Index(null, null, "Alpha", 5);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    // ── Index Pagination ───────────────────────────

    [Fact]
    public void Index_DefaultPage_ReturnsFirstPage()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_ReturnsPaginatedListModel()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.IsType<PaginatedList<Student>>(viewResult.Model);
    }

    // ── Index ViewBag ──────────────────────────────

    [Fact]
    public void Index_SetsViewBagSortParameters()
    {
        // Act — default (null) sortOrder
        var result = _controller.Index(null, null, null, null);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        // When sortOrder is null/empty: NameSortParm = "name_desc", DateSortParm = "Date"
        Assert.Equal("name_desc", viewResult.ViewData["NameSortParm"]);
        Assert.Equal("Date", viewResult.ViewData["DateSortParm"]);
        Assert.Null(viewResult.ViewData["CurrentSort"]);
    }

    // ── Details ────────────────────────────────────

    [Fact]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = new Student { LastName = "Doe", FirstMidName = "John", EnrollmentDate = new DateTime(2023, 9, 1) };
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(student.ID);

        // Assert
        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Doe", model.LastName);
        Assert.Equal("John", model.FirstMidName);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_IncludesEnrollmentsWithCourses()
    {
        // Arrange — seed department, course, student, enrollment
        var dept = new Department { Name = "Math", Budget = 100000, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 1001, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
