    }

    public void Dispose()
    {
        _controller.Dispose();
        NotificationQueueHelper.DrainQueue();
    }

    private static SchoolContext CreateContextForDb(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(dbName)
            .Options;
        return new SchoolContext(options);
    }

    private Instructor SeedInstructor()
    {
        var instructor = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = new DateTime(2002, 7, 6),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private Department SeedDepartment()
    {
        var instructor = SeedInstructor();
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructor.ID
        };
