    // ── Edit POST ──────────────────────────────────

    [Fact]
    public void EditPost_ValidDepartment_SavesAndRedirects()
    {
        // Arrange — seed in original context, then use a fresh context for the controller
        var instructor = SeedInstructor();
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructor.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        var deptId = dept.DepartmentID;
        var instructorId = instructor.ID;

        // Use a fresh context to avoid tracked-entity conflicts
        using var freshContext = CreateContextForDb(_dbName);
        using var freshController = new DepartmentsController(freshContext);
        var httpContext = new DefaultHttpContext();
        var tempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
        freshController.TempData = tempData;

        var editedDept = new Department
        {
            DepartmentID = deptId,
            Name = "Updated Engineering",
            Budget = 400000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = instructorId
        };

        // Act
        var result = freshController.Edit(editedDept);

        // Assert
        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);

        using var verifyContext = CreateContextForDb(_dbName);
        var saved = verifyContext.Departments.Find(deptId);
